WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/36.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/36.0/apex.js")} 

var stageName = '{!Opportunity.StageName}';

if(stageName == 'Template'){ 
    alert('You are currently looking at a template. Room Allocation is unavailable - please select a Tour.');	
} else if(stageName == 'Tour'){ 
    window.location = '/apex/{!$Setup.sugati__Site__c.sugati__Namespace__c}RoomAllocation?id={!Opportunity.Id}'; 
} else {	
    window.location = '/apex/{!$Setup.sugati__Site__c.sugati__Namespace__c}RoomAllocation?id={!Opportunity.sugati__O_Tour_Id__c}';	
}
